// ======================================================
// Modelo solicitado pelo usuário via Webhook
// ======================================================
//
// Exemplo recebido:
//
// {
//   "model": "claude-3.5-sonnet"
// }
//
// ou:
//
// {
//   "model": "anthropic/claude-3.5-sonnet"
// }
//
// Esse será o modelo que tentaremos resolver.
//
const requestedModel =
  $('Webhook').first().json.body.model;


// ======================================================
// Lista de modelos disponíveis atualmente na OpenRouter
// ======================================================
//
// Esse node faz:
// GET https://openrouter.ai/api/v1/models
//
// E retorna algo como:
//
// [
//   { id: "anthropic/claude-4-sonnet" },
//   { id: "openai/gpt-4.1" },
//   ...
// ]
//
const availableModels =
  $('Busca modelos no openRouter')
    .first()
    .json
    .data;


// ======================================================
// FUNÇÃO parseModel()
// ======================================================
//
// Objetivo:
// Transformar um nome de modelo em uma estrutura padronizada
// para facilitar comparações inteligentes.
//
// Exemplo:
//
// "anthropic/claude-3.5-sonnet"
//
// vira:
//
// {
//   provider: "anthropic",
//   family: "claude",
//   tier: "sonnet",
//   version: 3.5
// }
//
// Isso permite:
//
// - comparar providers
// - comparar versões
// - comparar tiers
// - encontrar equivalentes
//
function parseModel(model) {

  // transforma tudo em lowercase
  // para evitar problemas com maiúsculas/minúsculas
  const lower = model.toLowerCase();

  // provider = empresa/model provider
  // ex:
  // anthropic
  // openai
  // google
  let provider = '';

  // nome puro do modelo
  // ex:
  // claude-3.5-sonnet
  let name = '';

  // ======================================================
  // CASO 1:
  // Modelo possui provider
  //
  // Ex:
  // anthropic/claude-3.5-sonnet
  // ======================================================
  if (lower.includes('/')) {

    const parts = lower.split('/');

    provider = parts[0] || '';
    name = parts[1] || '';

  } else {

    // ======================================================
    // CASO 2:
    // Modelo NÃO possui provider
    //
    // Ex:
    // claude-3.5-sonnet
    // ======================================================

    name = lower;

    // inferimos o provider baseado no nome

    if (name.includes('claude')) {
      provider = 'anthropic';
    }
    else if (
      name.includes('gpt') ||
      name.includes('o1') ||
      name.includes('o3')
    ) {
      provider = 'openai';
    }
    else if (name.includes('gemini')) {
      provider = 'google';
    }
    else if (name.includes('llama')) {
      provider = 'meta-llama';
    }

  }

  // ======================================================
  // EXTRAÇÃO DA VERSÃO
  // ======================================================
  //
  // Procura números dentro do nome
  //
  // Ex:
  // claude-3.5-sonnet
  //
  // encontra:
  // 3.5
  //
  const versionMatch =
    name.match(/(\d+(\.\d+)?)/);

  const version =
    versionMatch
      ? parseFloat(versionMatch[1])
      : 0;

  // ======================================================
  // EXTRAÇÃO DO TIER
  // ======================================================
  //
  // Alguns providers possuem tiers:
  //
  // sonnet
  // opus
  // haiku
  // flash
  // mini
  // etc
  //
  // Isso ajuda a encontrar equivalentes.
  //
  let tier = '';

  if (name.includes('sonnet')) tier = 'sonnet';
  else if (name.includes('opus')) tier = 'opus';
  else if (name.includes('haiku')) tier = 'haiku';
  else if (name.includes('flash')) tier = 'flash';
  else if (name.includes('pro')) tier = 'pro';
  else if (name.includes('mini')) tier = 'mini';
  else if (name.includes('nano')) tier = 'nano';

  // ======================================================
  // EXTRAÇÃO DA FAMÍLIA
  // ======================================================
  //
  // Família = linha principal do modelo
  //
  // Ex:
  // claude
  // gpt
  // gemini
  // llama
  //
  let family = '';

  if (name.includes('claude')) family = 'claude';
  else if (name.includes('gpt')) family = 'gpt';
  else if (name.includes('gemini')) family = 'gemini';
  else if (name.includes('llama')) family = 'llama';

  // retorna estrutura padronizada
  return {
    raw: model,
    provider,
    name,
    version,
    tier,
    family
  };

}


// ======================================================
// Parse do modelo solicitado
// ======================================================
//
// Converte o modelo pedido pelo usuário
// em estrutura comparável.
//
const requested =
  parseModel(requestedModel);


// ======================================================
// Lista de IDs disponíveis
// ======================================================
//
// Transformamos:
//
// [
//   { id: "openai/gpt-4.1" },
//   { id: "anthropic/claude-4-sonnet" }
// ]
//
// em:
//
// [
//   "openai/gpt-4.1",
//   "anthropic/claude-4-sonnet"
// ]
//
const availableIds =
  availableModels.map(
    m => m.id.toLowerCase()
  );


// ======================================================
// MATCH EXATO
// ======================================================
//
// Primeiro tentamos encontrar exatamente
// o modelo solicitado.
//
// Ex:
//
// usuário pediu:
// anthropic/claude-4-sonnet
//
// e ele existe.
//
// então retornamos imediatamente.
//
if (
  availableIds.includes(
    requestedModel.toLowerCase()
  )
) {

  const exact =
    availableModels.find(
      m =>
        m.id.toLowerCase() ===
        requestedModel.toLowerCase()
    );

  return [{
    json: {
      requestedModel,

      // modelo final escolhido
      resolvedModel: exact.id,

      // fallback não foi necessário
      fallbackUsed: false,

      // estratégia utilizada
      strategy: 'exact'
    }
  }];

}


// ======================================================
// MATCH EXATO SEM PROVIDER
// ======================================================
//
// Caso o usuário mande:
//
// claude-3.5-sonnet
//
// ao invés de:
//
// anthropic/claude-3.5-sonnet
//
// tentamos comparar apenas o nome.
//
const shortExact =
  availableModels.find(m => {

    const parsed =
      parseModel(m.id);

    return (
      parsed.name ===
      requested.name
    );

  });

if (shortExact) {

  return [{
    json: {
      requestedModel,
      resolvedModel: shortExact.id,
      fallbackUsed: false,
      strategy: 'short_exact'
    }
  }];

}


// ======================================================
// BUSCA DE MODELOS EQUIVALENTES
// ======================================================
//
// Se não encontrou match exato,
// tentamos encontrar modelos parecidos.
//
// Primeiro:
//
// pegamos apenas modelos do mesmo provider
//
// Ex:
// se pediu Claude,
// não queremos retornar GPT.
//
const candidates =
  availableModels
    .map(m => ({
      id: m.id,

      // parse do modelo disponível
      parsed: parseModel(m.id)
    }))
    .filter(m =>
      m.parsed.provider ===
      requested.provider
    );


// ======================================================
// SISTEMA DE SCORE
// ======================================================
//
// Agora damos pontos para cada candidato.
//
// Quanto maior a pontuação,
// mais parecido com o modelo solicitado.
//
for (const candidate of candidates) {

  let score = 0;

  // ======================================================
  // MESMA FAMÍLIA
  // ======================================================
  //
  // Ex:
  // Claude -> Claude
  //
  // recebe muitos pontos
  //
  if (
    candidate.parsed.family ===
    requested.family
  ) {
    score += 100;
  }

  // ======================================================
  // MESMO TIER
  // ======================================================
  //
  // Ex:
  // Sonnet -> Sonnet
  //
  // recebe pontos extras
  //
  if (
    candidate.parsed.tier ===
    requested.tier
  ) {
    score += 80;
  }

  // ======================================================
  // VERSÃO PRÓXIMA
  // ======================================================
  //
  // Quanto mais próxima a versão,
  // maior o score.
  //
  // Ex:
  //
  // pediu 3.5
  //
  // 4.0 é melhor que 8.0
  //
  const diff =
    Math.abs(
      candidate.parsed.version -
      requested.version
    );

  score += Math.max(
    0,
    50 - diff * 10
  );

  // ======================================================
  // BÔNUS PARA VERSÃO MAIS NOVA
  // ======================================================
  //
  // Se a versão do candidato
  // for maior ou igual,
  // recebe bônus.
  //
  // Ex:
  // 4.0 substitui melhor 3.5
  // do que 2.0.
  //
  if (
    candidate.parsed.version >=
    requested.version
  ) {
    score += 20;
  }

  // salva score final
  candidate.score = score;

}


// ======================================================
// ORDENAÇÃO
// ======================================================
//
// Ordena do MAIOR score
// para o MENOR.
//
candidates.sort(
  (a, b) => b.score - a.score
);


// melhor candidato
const best = candidates[0];


// ======================================================
// CASO NÃO ENCONTRE NADA
// ======================================================
if (!best) {

  return [{
    json: {
      error:
        'Nenhum modelo equivalente encontrado',

      requestedModel
    }
  }];

}


// ======================================================
// RESULTADO FINAL
// ======================================================
//
// Retorna:
//
// - modelo solicitado
// - modelo resolvido
// - estratégia utilizada
// - score obtido
//
return [{
  json: {
    requestedModel,

    // modelo final escolhido
    resolvedModel: best.id,

    // indica que fallback foi usado
    fallbackUsed: true,

    // estratégia utilizada
    strategy: 'smart_fallback',

    // score do candidato vencedor
    score: best.score
  }
}];

