const requested =
  parseModel(requestedModel);


// ======================================================
// Lista de IDs disponíveis
// ======================================================
//
// Transformamos:
//
// [
//   { id: "openai/gpt-4.1" },
//   { id: "anthropic/claude-4-sonnet" }
// ]
//
// em:
//
// [
//   "openai/gpt-4.1",
//   "anthropic/claude-4-sonnet"
// ]
//
const availableIds =
  availableModels.map(
    m => m.id.toLowerCase()
  );


// ======================================================
// MATCH EXATO
// ======================================================
//
// Primeiro tentamos encontrar exatamente
// o modelo solicitado.
//
