  availableIds.includes(
    requestedModel.toLowerCase()
  )
) {

  const exact =
    availableModels.find(
      m =>
        m.id.toLowerCase() ===
        requestedModel.toLowerCase()
    );

  return [{
    json: {
      requestedModel,

      // modelo final escolhido
      resolvedModel: exact.id,

      // fallback não foi necessário
      fallbackUsed: false,

      // estratégia utilizada
      strategy: 'exact'
    }
  }];

