  availableModels.find(m => {

    const parsed =
      parseModel(m.id);

    return (
      parsed.name ===
      requested.name
    );

  });

if (shortExact) {

  return [{
    json: {
      requestedModel,
      resolvedModel: shortExact.id,
      fallbackUsed: false,
      strategy: 'short_exact'
